#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Maps;
using MVZ2.GameContent.Stages;
using MVZ2.GameContent.Talk;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Maps;
using MVZ2Logic.Saves;
using MVZ2Logic.Unlocks;
using PVZEngine;
using Tools;

namespace MVZ2.GameContent.IZombie
{
    [AutoMapElementBehaviourDefinition(VanillaMapElementBehaviourNames.nightmareBox)]
    public class NightmareBoxMapElement : MapElementBehaviourDefinition
    {
        public NightmareBoxMapElement(string nsp, string name) : base(nsp, name)
        {
        }
        public override void OnClick(IMapElement element)
        {
            var map = element.Map;
            Global.Saves.SetDreamIsNightmare(!Global.Saves.DreamIsNightmare());
            map.ChangeMap(map.GetMapID());
        }
    }
}
